        {
            audioSource.Play();
        }
    }

    public float GetSongTime()
    {
        if (audioSource == null) return 0f;
        return audioSource.time - songOffset;
    }

    public float GetCurrentBeat()
    {
        return GetSongTime() / secondsPerBeat;
    }

    public float GetSecondsPerBeat()
    {
        return secondsPerBeat;
    }
}

