        if (RhythmManager.Instance == null)
        {
            Debug.LogWarning("HitJudge: RhythmManager.Instance is missing.");
            return;
        }

        LineSegment currentLine = lineManager.GetCurrentLine();
        if (currentLine == null)
        {
            Debug.Log("No current line.");
            return;
        }

        MusicLineData lineData = currentLine.GetLineData();
        if (lineData == null || lineData.notes == null || lineData.notes.Count == 0)
        {
            Debug.Log("No notes in current line.");
            return;
        }

        float currentBeat = RhythmManager.Instance.GetCurrentBeat();

        List<HitTarget> targets = new List<HitTarget>();

        for (int i = 0; i < lineData.notes.Count; i++)
        {
            NoteEvent note = lineData.notes[i];

            // QUARTER NOTE (1 hit)
            if (note.noteType == NoteType.Quarter)
            {
                string hitId = i + "_0";

                if (!usedHits.Contains(hitId))
                {
                    targets.Add(new HitTarget
                    {
                        noteIndex = i,
                        beat = lineData.startBeat + note.beatPosition,
                        hitId = hitId
                    });
                }
            }

            // EIGHTH PAIR (2 hits)
            else if (note.noteType == NoteType.EighthPair)
            {
                string firstHitId = i + "_0";
                string secondHitId = i + "_1";

                // first eighth
                if (!usedHits.Contains(firstHitId))
                {
                    targets.Add(new HitTarget
                    {
                        noteIndex = i,
                        beat = lineData.startBeat + note.beatPosition,
                        hitId = firstHitId
                    });
                }

                // second eighth (half beat later)
                if (!usedHits.Contains(secondHitId))
                {
                    targets.Add(new HitTarget
                    {
                        noteIndex = i,
                        beat = lineData.startBeat + note.beatPosition + 0.5f,
                        hitId = secondHitId
                    });
                }
            }
        }

        if (targets.Count == 0)
        {
            Debug.Log("No available note found.");
            return;
        }

        HitTarget closestTarget = null;
        float closestAbsDelta = Mathf.Infinity;
        float closestDelta = 0f;

        for (int i = 0; i < targets.Count; i++)
        {
            float delta = currentBeat - targets[i].beat;
            float absDelta = Mathf.Abs(delta);

            if (absDelta < closestAbsDelta)
            {
                closestAbsDelta = absDelta;
                closestDelta = delta;
                closestTarget = targets[i];
            }
        }

        if (closestTarget == null)
        {
            Debug.Log("No available note found.");
            return;
        }

        if (closestAbsDelta > missWindow)
        {
            Debug.Log("MISS - too far from note");
            return;
        }

        usedHits.Add(closestTarget.hitId);

        string timingSide;
        if (closestDelta < -0.01f)
            timingSide = "EARLY";
        else if (closestDelta > 0.01f)
            timingSide = "LATE";
        else
            timingSide = "ON TIME";

        if (closestAbsDelta <= perfectWindow)
        {
            Debug.Log("PERFECT - " + timingSide + " - delta: " + closestDelta.ToString("F3"));
        }
        else if (closestAbsDelta <= goodWindow)
        {
            Debug.Log("GOOD - " + timingSide + " - delta: " + closestDelta.ToString("F3"));
        }
        else
        {
            Debug.Log("OK - " + timingSide + " - delta: " + closestDelta.ToString("F3"));
        }
    }
}

public void AdvanceLine()
    {
        StartCoroutine(AdvanceLineAnimated());
    }

using UnityEngine;

[RequireComponent(typeof(Rigidbody2D))]
public class birdscript : MonoBehaviour
{
    public AudioSource drumSound;
    public float jumpForce = 7f;
    public LayerMask groundLayer;
    public float groundCheckDistance = 0.3f;

    private Rigidbody2D rb;

    public bool allowAutoMove = true;

    void Awake()
    {
        rb = GetComponent<Rigidbody2D>();
    }

    void FixedUpdate()
    {
        // Do not auto-move horizontally here.
        // LineManager will control the X position.
    }

    void Update()
    {
        if (Input.GetKeyDown(KeyCode.Space) && IsGrounded())
        {
            rb.linearVelocity = new Vector2(rb.linearVelocity.x, jumpForce);

            if (drumSound != null)
            {
                drumSound.Play();
            }
        }
    }

    bool IsGrounded()
    {
        RaycastHit2D hit = Physics2D.Raycast(
            transform.position,
            Vector2.down,
            groundCheckDistance,
            groundLayer
        );

        return hit.collider != null;
    }
}

using System.Collections;
using UnityEngine;

public class LineManager : MonoBehaviour
{
    public LineSegment linePrefab;

    public Vector3 currentLinePosition = new Vector3(-8f, 0.05f, 0f);
    public Vector3 previewLinePosition = new Vector3(-8f, -0.05f, 0f);

    public Transform player;
    public float playerStartX = -7f;
    public float playerEndX = 7f;
    public float playerY = 0f;

    public float sideSwitchDuration = 0.2f;

    private LineSegment currentLine;
    private LineSegment previewLine;

    private bool isSwitching = false;

    private birdscript bird;

    void Start()
    {
        SpawnInitialLines();

        if (player != null)
        {
            player.position = new Vector3(playerStartX, playerY, player.position.z);
            bird = player.GetComponent<birdscript>();
        }
    }

    void Update()
    {
        if (isSwitching) return;
        if (currentLine == null) return;
        if (RhythmManager.Instance == null) return;

        MusicLineData currentData = currentLine.GetLineData();
        if (currentData == null) return;

        float currentBeat = RhythmManager.Instance.GetCurrentBeat();
        float beatInLine = currentBeat - currentData.startBeat;

        float t = Mathf.Clamp01(beatInLine / currentData.TotalBeats);

        UpdatePlayerPosition(t);

        if (beatInLine >= currentData.TotalBeats)
        {
            StartCoroutine(AdvanceLineAnimated());
        }
    }

    public void AdvanceLine()
    {
        if (!isSwitching)
        {
            StartCoroutine(AdvanceLineAnimated());
        }
    }

    IEnumerator AdvanceLineAnimated()
    {
        isSwitching = true;

        if (bird != null)
            bird.allowAutoMove = false;

        Vector3 startPos = player.position;
        Vector3 endPos = new Vector3(playerStartX, player.position.y, startPos.z);

        float elapsed = 0f;

        while (elapsed < sideSwitchDuration)
        {
            elapsed += Time.deltaTime;
            float t = Mathf.Clamp01(elapsed / sideSwitchDuration);
            player.position = Vector3.Lerp(startPos, endPos, t);
            yield return null;
        }

        player.position = endPos;

        if (currentLine != null)
            Destroy(currentLine.gameObject);

        currentLine = previewLine;
        currentLine.transform.position = currentLinePosition;
        SetCurrentLook(currentLine);

        MusicLineData currentData = currentLine.GetLineData();

        MusicLineData newPreviewData = RhythmGenerator.GenerateRandomLine();
        newPreviewData.startBeat = currentData.startBeat + currentData.TotalBeats;

        previewLine = Instantiate(linePrefab, previewLinePosition, Quaternion.identity);
        previewLine.BuildLine(newPreviewData);
        SetPreviewLook(previewLine);

        if (bird != null)
            bird.allowAutoMove = true;

        isSwitching = false;
    }

    void SpawnInitialLines()
    {
        MusicLineData currentData = RhythmGenerator.GenerateRandomLine();
        currentData.startBeat = 0f;

        MusicLineData previewData = RhythmGenerator.GenerateRandomLine();
        previewData.startBeat = currentData.startBeat + currentData.TotalBeats;

        currentLine = Instantiate(linePrefab, currentLinePosition, Quaternion.identity);
        currentLine.BuildLine(currentData);

        previewLine = Instantiate(linePrefab, previewLinePosition, Quaternion.identity);
        previewLine.BuildLine(previewData);

        SetPreviewLook(previewLine);
    }

    void UpdatePlayerPosition(float t)
    {
        if (player == null) return;

        float x = Mathf.Lerp(playerStartX, playerEndX, t);
        player.position = new Vector3(x, player.position.y, player.position.z);
    }

    void SetPreviewLook(LineSegment line) { }
    void SetCurrentLook(LineSegment line) { }

    public LineSegment GetCurrentLine()
    {
        return currentLine;
    }
}
